package org.springframework.ai.aot;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import org.springframework.aot.hint.RuntimeHints;
import org.springframework.aot.hint.RuntimeHintsRegistrar;
import org.springframework.lang.Nullable;
import org.springframework.ai.tool.execution.DefaultToolCallResultConverter;
import org.junit.jupiter.api.Assertions;
import org.springframework.aot.hint.MemberCategory;
import org.springframework.lang.NonNull;

public class ToolRuntimeHintsTest {

    private final RuntimeHintsRegistrar toolRuntimeHints = Mockito.mock(RuntimeHintsRegistrar.class);

    @Test
    public void registerDefaultToolCallResultConverter() {
        RuntimeHints runtimeHints = new RuntimeHints();
        MemberCategory[] memberCategories = MemberCategory.values();

        toolRuntimeHints.registerHints(runtimeHints, null);

        for (MemberCategory memberCategory : memberCategories) {
            Assertions.assertTrue(
                runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
                "DefaultToolCallResultConverter must be registered for reflection!"
            );
        }
    }

    @Test
    public void handleNullClassLoader() {
        RuntimeHints runtimeHints = new RuntimeHints();

        toolRuntimeHints.registerHints(runtimeHints, null);

        Assertions.assertTrue(
            runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
            "DefaultToolCallResultConverter should still be registered for reflection with null ClassLoader."
        );
    }

    @Test
    public void testEmptyMemberCategoryArray() {
        RuntimeHints runtimeHints = Mockito.mock(RuntimeHints.class);
        RuntimeHints.ReflectionHints reflectionHints = Mockito.mock(RuntimeHints.ReflectionHints.class);
        Mockito.when(runtimeHints.reflection()).thenReturn(reflectionHints);

        toolRuntimeHints.registerHints(runtimeHints, null);

        Mockito.verify(reflectionHints).registerType(Mockito.eq(DefaultToolCallResultConverter.class), Mockito.any(MemberCategory[].class));
    }

    @Test
    public void preExistingReflectionConfiguration() {
        RuntimeHints runtimeHints = new RuntimeHints();
        runtimeHints.reflection().registerType(String.class, MemberCategory.INVOKE_PUBLIC_METHODS);

        toolRuntimeHints.registerHints(runtimeHints, null);

        Assertions.assertTrue(
            runtimeHints.reflection().isRegistered(String.class),
            "Pre-existing reflection configuration must remain."
        );
        Assertions.assertTrue(
            runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
            "DefaultToolCallResultConverter should be registered for reflection."
        );
    }

    @Test
    public void handleMultipleClassLoaders() {
        RuntimeHints runtimeHints = new RuntimeHints();
        ClassLoader customClassLoader = Mockito.mock(ClassLoader.class);

        toolRuntimeHints.registerHints(runtimeHints, customClassLoader);

        Assertions.assertTrue(
            runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
            "Registration of DefaultToolCallResultConverter must be unaffected by differing ClassLoader inputs."
        );
    }

    @Test
    public void validateMemberCategoryUsage() {
        RuntimeHints runtimeHints = new RuntimeHints();
        MemberCategory[] memberCategories = MemberCategory.values();

        toolRuntimeHints.registerHints(runtimeHints, null);

        for (MemberCategory category : memberCategories) {
            Assertions.assertTrue(
                runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
                "All MemberCategory values should be utilized in reflection registration."
            );
        }
    }

    @Test
    public void handleRuntimeHintsException() {
        RuntimeHints runtimeHints = Mockito.mock(RuntimeHints.class);
        RuntimeHints.ReflectionHints reflectionHints = Mockito.mock(RuntimeHints.ReflectionHints.class);
        Mockito.when(runtimeHints.reflection()).thenReturn(reflectionHints);
        Mockito.doThrow(RuntimeException.class).when(reflectionHints)
            .registerType(Mockito.eq(DefaultToolCallResultConverter.class), Mockito.any(MemberCategory[].class));

        Assertions.assertDoesNotThrow(() -> toolRuntimeHints.registerHints(runtimeHints, null),
            "The method should handle exceptions gracefully during reflection registration.");
    }

    @Test
    public void checkReflectionRegistrationValidity() {
        RuntimeHints runtimeHints = new RuntimeHints();

        toolRuntimeHints.registerHints(runtimeHints, null);

        Assertions.assertTrue(
            runtimeHints.reflection().isRegistered(DefaultToolCallResultConverter.class),
            "DefaultToolCallResultConverter should be registered for reflection with valid MemberCategory values."
        );
    }

    @Test
    public void handleNullRuntimeHintsArgument() {
        Assertions.assertThrows(
            NullPointerException.class,
            () -> toolRuntimeHints.registerHints(null, ClassLoader.getSystemClassLoader()),
            "Null RuntimeHints argument should throw a NullPointerException."
        );
    }
}
